const { createCanvas } = require('canvas');
const fs = require('fs');
const path = require('path');

const IMG = {
  BG: '#1E1E2E', PANEL_BG: '#2A2A3E', HEADER: '#CDD6F4',
  TEXT: '#BAC2DE', DIM: '#6C7086', ACCENT: '#89B4FA',
  GREEN: '#2ECC71', YELLOW: '#F1C40F', RED: '#E74C3C',
  GRAY: '#7F8C8D', CYAN: '#00BCD4'
};

function truncate(s, max) { return s.length > max ? s.substring(0, max - 1) + '…' : s; }

const sessions = [
  { agent_name: 'Guru', status: 'activa', action: 'WebSearch: Ktor routing', duration: '12m', actions: 8, task: 'Investigando patrón de rutas dinámicas' },
  { agent_name: 'Tester', status: 'activa', action: 'Bash: ./gradlew check', duration: '5m', actions: 15, task: 'Ejecutando tests de backend' },
  { agent_name: 'Builder', status: 'idle', action: 'Build completo', duration: '22m', actions: 4, task: null },
  { agent_name: 'QA', status: 'activa', action: 'Bash: qa-android.sh', duration: '3m', actions: 6, task: 'E2E signup flow Android' },
  { agent_name: 'DeliveryManager', status: 'done', action: 'PR #1008 creado', duration: '45m', actions: 12, task: null },
];

const git = { branch: 'main' };

const W = 800;
const agentRows = sessions.length;
const taskRows = sessions.filter(s => s.task && s.status !== 'done').length;
const H = Math.max(420, 110 + (agentRows * 32) + (taskRows * 20) + 130);

const canvas = createCanvas(W, H);
const ctx = canvas.getContext('2d');

ctx.fillStyle = IMG.BG;
ctx.fillRect(0, 0, W, H);
ctx.textBaseline = 'top';

let y = 0;

// HEADER
ctx.fillStyle = IMG.PANEL_BG;
ctx.fillRect(0, y, W, 50);
ctx.fillStyle = IMG.ACCENT;
ctx.fillRect(0, y + 48, W, 2);

ctx.font = 'bold 18px monospace';
ctx.fillStyle = IMG.HEADER;
ctx.fillText('Sprint Monitor', 16, y + 14);

const timeStr = new Date().toTimeString().substring(0, 8);
ctx.font = '14px monospace';
ctx.fillStyle = IMG.DIM;
ctx.fillText(timeStr + '  |  ' + git.branch, W - 380, y + 18);
y += 56;

// PANEL AGENTES
ctx.font = 'bold 14px monospace';
ctx.fillStyle = IMG.ACCENT;
ctx.fillText('AGENTES', 16, y);
y += 22;

for (const s of sessions) {
  const statusColor = s.status === 'activa' ? IMG.GREEN : s.status === 'idle' ? IMG.YELLOW : IMG.GRAY;

  ctx.fillStyle = statusColor;
  ctx.fillRect(16, y, 4, 22);

  ctx.beginPath();
  ctx.arc(32, y + 11, 5, 0, Math.PI * 2);
  ctx.fillStyle = statusColor;
  ctx.fill();

  ctx.font = 'bold 14px monospace';
  ctx.fillStyle = IMG.HEADER;
  ctx.fillText(truncate(s.agent_name, 20), 44, y + 3);

  ctx.font = '14px monospace';
  ctx.fillStyle = IMG.TEXT;
  ctx.fillText(s.action, 240, y + 3);

  ctx.fillStyle = IMG.DIM;
  ctx.fillText(s.duration, 490, y + 3);

  ctx.fillStyle = IMG.CYAN;
  ctx.fillText(s.actions + ' accs', 560, y + 3);

  ctx.fillStyle = statusColor;
  ctx.fillText(s.status, 650, y + 3);

  y += 28;

  if (s.task && s.status !== 'done') {
    ctx.font = '12px monospace';
    ctx.fillStyle = IMG.DIM;
    ctx.fillText('  > ' + truncate(s.task, 65), 44, y);
    y += 20;
  }
}
y += 8;

// PANEL CI
ctx.fillStyle = IMG.PANEL_BG;
ctx.fillRect(0, y, W, 44);
ctx.fillStyle = IMG.ACCENT;
ctx.fillRect(0, y, W, 1);
y += 8;

ctx.font = 'bold 14px monospace';
ctx.fillStyle = IMG.ACCENT;
ctx.fillText('CI', 16, y);

ctx.font = '14px monospace';
ctx.fillStyle = IMG.GREEN;
ctx.fillText('OK success', 50, y);
ctx.fillStyle = IMG.DIM;
ctx.fillText('(main)', 240, y);
y += 36;

// PANEL METRICAS
ctx.fillStyle = IMG.ACCENT;
ctx.fillRect(0, y, W, 1);
y += 8;

ctx.font = 'bold 14px monospace';
ctx.fillStyle = IMG.ACCENT;
ctx.fillText('METRICAS', 16, y);
y += 22;

const metrics = [
  { label: 'Activos', value: '3', color: IMG.GREEN },
  { label: 'Idle', value: '1', color: IMG.YELLOW },
  { label: 'Total', value: '5', color: IMG.HEADER },
];

let mx = 30;
for (const m of metrics) {
  ctx.fillStyle = IMG.PANEL_BG;
  ctx.fillRect(mx, y, 100, 36);
  ctx.strokeStyle = m.color;
  ctx.lineWidth = 1;
  ctx.strokeRect(mx, y, 100, 36);

  ctx.font = 'bold 18px monospace';
  ctx.fillStyle = m.color;
  ctx.fillText(m.value, mx + 12, y + 4);

  ctx.font = '12px monospace';
  ctx.fillStyle = IMG.DIM;
  ctx.fillText(m.label, mx + 40, y + 10);

  mx += 130;
}

// Recortar al alto real
const finalH = y + 50;
const finalCanvas = createCanvas(W, finalH);
const fctx = finalCanvas.getContext('2d');
fctx.drawImage(canvas, 0, 0);

const outPath = path.join(__dirname, 'monitor-example.png');
fs.writeFileSync(outPath, finalCanvas.toBuffer('image/png'));
console.log('Imagen generada: ' + outPath);
console.log('Dimensiones: ' + W + 'x' + finalH);

