cd /c/Workspaces/Intrale/platform && node -e "
const fs = require('fs');
const https = require('https');
const path = require('path');

const config = JSON.parse(fs.readFileSync('.claude/hooks/telegram-config.json', 'utf8'));
const TOKEN = config.bot_token;
const CHAT_ID = String(config.chat_id);

// Leer la imagen de ejemplo que generamos antes
const imgBuf = fs.readFileSync('.claude/tmp/monitor-example.png');
const caption = 'Test reporter PNG automatico - cada 5 min';

const CRLF = '\r\n';
const boundary = 'boundary' + Date.now();

const parts = 
  '--' + boundary + CRLF +
  'Content-Disposition: form-data; name=\"chat_id\"' + CRLF + CRLF +
  CHAT_ID + CRLF +
  '--' + boundary + CRLF +
  'Content-Disposition: form-data; name=\"caption\"' + CRLF + CRLF +
  caption + CRLF +
  '--' + boundary + CRLF +
  'Content-Disposition: form-data; name=\"photo\"; filename=\"dashboard.png\"' + CRLF +
  'Content-Type: image/png' + CRLF + CRLF;

const tail = CRLF + '--' + boundary + '--' + CRLF;

const body = Buffer.concat([Buffer.from(parts), imgBuf, Buffer.from(tail)]);

const req = https.request({
  hostname: 'api.telegram.org',
  path: '/bot' + TOKEN + '/sendPhoto',
  method: 'POST',
  headers: {
    'Content-Type': 'multipart/form-data; boundary=' + boundary,
    'Content-Length': body.length
  }
}, (res) => {
  let data = '';
  res.on('data', c => data += c);
  res.on('end', () => {
    const r = JSON.parse(data);
    console.log('ok:', r.ok);
    if (!r.ok) console.log('error:', r.description);
    else console.log('Imagen enviada a Telegram OK');
  });
});
req.write(body);
req.end();
" 2>&1

